#include<bits/stdc++.h>
using namespace std;
int n,r;
long long dfs(int x,int y){
	if(y==0){
		return 0;
	}
	if(y==1||x==y){
		return 1;
	}
    return dfs(x-1,y-1)+y*dfs(x-1,y);
}
long long jie(int x){
    if(x==1) return 1;
    return jie(x-1)*x;
}
int main() {
	cin>>n>>r;
	cout<<jie(r)*dfs(n,r);
}
